Here's a modern MSTest test class for `DataFetcher` covering success, failure, cancellation, and timeout scenarios:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello world"),
        });
        var sut = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await sut.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFoundResponse_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.NotFound));
        var sut = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("data"),
        }, delay: TimeSpan.FromSeconds(30)); // simulate slow response
        var sut = new DataFetcher(new HttpClient(handler));

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_WithTimeout_CompletesWithinLimit()
    {
        // TestContext.CancellationToken is signaled when [Timeout] expires,
        // giving the test cooperative cancellation instead of a hard abort.
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("fast"),
        });
        var sut = new DataFetcher(new HttpClient(handler));

        var result = await sut.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    [Timeout(1000)]
    public async Task FetchAsync_SlowResponse_CanceledByTimeout()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("slow"),
        }, delay: TimeSpan.FromSeconds(30));
        var sut = new DataFetcher(new HttpClient(handler));

        // The [Timeout] fires after 1s, signaling CancellationToken
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await sut.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    /// <summary>
    /// Fake HttpMessageHandler that returns a canned response,
    /// optionally after a delay that respects cancellation.
    /// </summary>
    private sealed class FakeHandler(
        HttpResponseMessage response,
        TimeSpan delay = default) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay > TimeSpan.Zero)
            {
                await Task.Delay(delay, cancellationToken);
            }

            return response;
        }
    }
}
```

**Key patterns used:**

- **`TestContext` via constructor** — enables `readonly` and nullability safety
- **`TestContext.CancellationToken`** — cooperates with `[Timeout]` so slow tests cancel cleanly instead of hard-aborting
- **`Assert.ThrowsExactlyAsync<T>`** — matches the exact exception type, replacing the obsolete `[ExpectedException]`
- **`FakeHandler`** — a custom `HttpMessageHandler` avoids mocking frameworks and gives full control over delay/cancellation behavior
- **Sealed test class** — best practice for performance
